# 使用 pyflakes 风格检查：查找未使用的 import
import ast, os

for fn in sorted(os.listdir('src')):
    if not fn.endswith('.py') or fn == '__init__.py':
        continue
    fp = os.path.join('src', fn)
    with open(fp) as f:
        source = f.read()
    tree = ast.parse(source)

    # Collect all imported names
    imported = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                name = alias.asname or alias.name
                imported[name] = node.lineno
        elif isinstance(node, ast.ImportFrom):
            for alias in node.names:
                name = alias.asname or alias.name
                imported[name] = node.lineno

    # Check which names are actually used (simple text search)
    for name, lineno in sorted(imported.items(), key=lambda x: x[1]):
        # Count occurrences in source (excluding the import line itself)
        lines = source.split('\n')
        count = 0
        for i, line in enumerate(lines, 1):
            if i == lineno:
                continue
            if name in line:
                count += 1
        if count == 0:
            print(f'{fp}:{lineno}: possibly unused import \"{name}\"')
